var n=document.getElementById("statusDot"),s=document.getElementById("statusText"),c=document.getElementById("appName"),a=document.getElementById("qlikUrl"),o=document.getElementById("wsUrl"),l=document.getElementById("saveBtn"),d=document.getElementById("reconnectBtn"),t=chrome.runtime.connect({name:"popup"});t.onMessage.addListener(e=>{e.type==="status"&&r(e.state)});function r(e){e.connected?(n.className="status-dot connected",s.textContent="Connected to MCP server"):(n.className="status-dot disconnected",s.textContent="Disconnected from MCP server"),c.textContent=e.currentAppName||"None",a.textContent=e.qlikTabId?"Active":"-",o.value=e.wsUrl}l.addEventListener("click",()=>{let e=o.value.trim();e&&t.postMessage({type:"set-ws-url",url:e})});d.addEventListener("click",()=>{t.postMessage({type:"reconnect"})});
